#include "../../headers/exceptions/ErrorArchivo.h"

ErrorArchivo::ErrorArchivo() : msg("Ha ocurrido un error durante la manipulacion del archivo.") {}

ErrorArchivo::ErrorArchivo(string mensaje) : msg("Ha ocurrido un error durante la manipulacion del archivo." + (mensaje.empty() ? string() : " (" + mensaje + ")")) {}

const char* ErrorArchivo::what() const noexcept
{
    return msg.c_str();
}

string ErrorArchivo::obtenerMensaje() const {
    return msg;
}

